const P = {
  cos: 0.6040719999999999,
  fxMin: -3.8767760659868813,
  dw: 4.941704309100723,
  maxLat: 55.81105823863513,
  dh: 5.946308777782157,
  pad: 8,
  w: 332,
  h: 400,
};

/** Project a lng/lat to the map's SVG coordinate space. Returns null if well off-map. */
export function projectPin(lng: number, lat: number): { x: number; y: number } | null {
  const x = P.pad + ((lng * P.cos - P.fxMin) / P.dw) * (P.w - 2 * P.pad);
  const y = P.pad + ((P.maxLat - lat) / P.dh) * (P.h - 2 * P.pad);
  if (x < -P.w * 0.15 || x > P.w * 1.15 || y < -P.h * 0.15 || y > P.h * 1.15) return null;
  return { x: Math.round(x * 10) / 10, y: Math.round(y * 10) / 10 };
}
